#include <bits/stdc++.h>
using namespace std;

const int N=1e7+10;

int n,prime[N],f[N],mu[N],s[N],cnt;
bool np[N];
long long ans;

int main(){
    scanf("%d",&n);
    np[0]=np[1]=1;
    mu[1]=1;
    for(int i=2;i<=n;i++){
        if(!np[i]){
            prime[++cnt]=i;
            f[i]=i,mu[i]=-1;
        }
        for(int j=1;j<=cnt && 1LL*prime[j]*i<=n;j++){
            np[prime[j]*i]=1;
            f[prime[j]*i]=prime[j];
            if(prime[j]==f[i])
                mu[prime[j]*i]=0;
            else
                mu[prime[j]*i]=-mu[i];
            if(i%prime[j]==0)
                break;
        }
    }
    for(int i=1;i<=n;i++)
        s[i]=s[i-1]+mu[i];
    for(int i=1;i<=cnt;i++){
        int p=prime[i];
        for(int j=1,r;j<=n/p;j=r+1){
            r=(n/p)/((n/p)/j);
            ans+=1LL*(s[r]-s[j-1])*(n/j/p)*(n/j/p);
        }
    }
    printf("%lld",ans);
    return 0;
}
